import React from 'react'

export default function Project({ name, short, technologies, description, onPress }) {

  return (
    <div className="project" onClick={onPress}>
      <div className="project-container">
        <h5>{name}</h5>
        <p>{short}</p>
        <div className="technologies">
          {
            false && technologies.map((technology, index) => {
              return <span key={index} className="uk-margin-small">{technology}</span>
            })
          }
        </div>
      </div>
    </div>
  )
}
