import React from 'react'
import { Parser } from 'html-to-react';

import Job from './Job';

export default function Experience({ jobs }) {

  return (
    <section id="experience">
      <h3 className="heading">الخبرة</h3>

      {
        jobs.map(({ company, time, position, description, technologies }, index) => {
          const htmlToReactParser = new Parser();
          const jobDescription = htmlToReactParser.parse(description);
          return (
            <Job key={index} company={company} time={time} position={position} description={jobDescription} technologies={technologies} />
          )
        })
      }

      <div>
        <div className="download">
          <a
            href="https://mrzalyaul.dev/CV_ZALYAUL_Mohammed_Rabie.pdf"
            className="arrow-link"
            download
          >
            تحميل السيرة الذاتية
            </a>
        </div>
      </div>
    </section>
  )
}
